@app.route('/users', methods=['GET'])
@handle_errors
def list_users():
    page = int(request.args.get('page', 1))
    limit = int(request.args.get('limit', 10))
    skip = (page - 1) * limit
    
    role = request.args.get('role')
    query = {}
    if role:
        query['role'] = role
    
    users = list(users_collection.find(query).skip(skip).limit(limit))
