@app.route('/documents', methods=['GET'])
@handle_errors
def query_documents():
    page = int(request.args.get('page', 1))
    limit = int(request.args.get('limit', 10))
    skip = (page - 1) * limit
    
    query = {}
    
    status = request.args.get('status')
    if status:
        query['status'] = status
    
    author_id = request.args.get('author_id')
    if author_id:
        query['author_id'] = author_id
    
    category = request.args.get('category')
    if category:
        query['category'] = category
    
    tags = request.args.get('tags')
    if tags:
        tag_list = tags.split(',')
        query['tags'] = {'$in': tag_list}
    
    search = request.args.get('search')
    if search:
        query['$or'] = [
            {'title': {'$regex': search, '$options': 'i'}},
            {'content': {'$regex': search, '$options': 'i'}}
        ]
    
    sort_by = request.args.get('sort_by', 'created_at')
    sort_order = -1 if request.args.get('sort_order', 'desc') == 'desc' else 1
    
    documents = list(documents_collection.find(query).sort(sort_by, sort_order).skip(skip).limit(limit))
    total = documents_collection.count_documents(query)
    
    for doc in documents:
        doc['_id'] = str(doc['_id'])
    
    return jsonify({
        'documents': documents,
        'total': total,
        'page': page,
        'limit': limit
    }), 200

