@app.route('/analytics/trending-documents', methods=['GET'])
@handle_errors
def trending_documents():
    limit = int(request.args.get('limit', 10))
    days = int(request.args.get('days', 7))
    
    from datetime import timedelta
    cutoff_date = datetime.utcnow() - timedelta(days=days)
    
    pipeline = [
        {
            '$match': {
                'created_at': {'$gte': cutoff_date}
            }
        },
        {
            '$addFields': {
                'engagement_score': {
                    '$add': [
                        {'$multiply': ['$views', 1]},
                        {'$multiply': ['$likes', 5]}
                    ]
                }
            }
        },
        {
            '$sort': {'engagement_score': -1}
        },
        {
            '$limit': limit
        },
        {
            '$project': {
                'title': 1,
                'author_id': 1,
                'views': 1,
                'likes': 1,
                'engagement_score': 1,
                'created_at': 1
            }
        }
    ]
    
    results = list(documents_collection.aggregate(pipeline))
    
    for doc in results:
        doc['_id'] = str(doc['_id'])
    
    return jsonify({'trending_documents': results}), 200

@app.route('/analytics/user-activity', methods=['GET'])
@handle_errors
def user_activity():
    pipeline = [
        {
            '$lookup': {
                'from': 'documents',
                'localField': '_id',
                'foreignField': 'author_id',
                'as': 'documents'
            }
        },
        {
            '$project': {
                'username': 1,
                'email': 1,
                'role': 1,
                'document_count': {'$size': '$documents'},
                'total_views': {'$sum': '$documents.views'},
                'total_likes': {'$sum': '$documents.likes'}
            }
        },
        {
            '$sort': {'document_count': -1}
        }
    ]
    
    results = list(users_collection.aggregate(pipeline))
    
    for user in results:
        user['_id'] = str(user['_id'])
    
    return jsonify({'user_activity': results}), 200

